 sources: [
 { title: 'Public Records', url: 'https://www.documentcloud.org/', type: 'Government' },
 ],
 affiliations: [
 { id: '1', name: 'SEC', type: 'agency', relationship: 'SPAC fraud enforcement', href: '/entities/agencies/sec' },
 ],
